/**
 * Delegate click events from a container to matching descendants.
 * @param {Element} container
 * @param {string} selector
 * @param {(target: Element, event: MouseEvent) => void} callback
 * @returns {() => void}
 */
export function delegateClicks(container, selector, callback) {
  const listener = (event) => {
    const target = event.target;
    if (!(target instanceof Element)) {
      return;
    }
    const match = target.closest(selector);
    if (!match || !container.contains(match)) {
      return;
    }
    callback(match, event);
  };

  container.addEventListener('click', listener);
  return () => container.removeEventListener('click', listener);
}
